import { Router } from "express";
import { db } from "@workspace/db";
import { animeTable, charactersTable } from "@workspace/db";
import { eq, sql } from "drizzle-orm";

const router = Router();

router.get("/anime", async (req, res) => {
  try {
    const anime = await db.select({
      id: animeTable.id,
      name: animeTable.name,
      nameAr: animeTable.nameAr,
      genre: animeTable.genre,
      imageUrl: animeTable.imageUrl,
      description: animeTable.description,
      characterCount: sql<number>`(select count(*) from characters where anime_id = ${animeTable.id})::int`,
    }).from(animeTable).orderBy(animeTable.name);
    res.json(anime);
  } catch (err) {
    req.log.error({ err }, "Failed to list anime");
    res.status(500).json({ error: "Failed to list anime" });
  }
});

router.get("/anime/:id", async (req, res) => {
  try {
    const id = parseInt(req.params.id);
    if (isNaN(id)) return res.status(400).json({ error: "Invalid id" });
    const [anime] = await db.select({
      id: animeTable.id,
      name: animeTable.name,
      nameAr: animeTable.nameAr,
      genre: animeTable.genre,
      imageUrl: animeTable.imageUrl,
      description: animeTable.description,
      characterCount: sql<number>`(select count(*) from characters where anime_id = ${animeTable.id})::int`,
    }).from(animeTable).where(eq(animeTable.id, id));
    if (!anime) return res.status(404).json({ error: "Not found" });
    res.json(anime);
  } catch (err) {
    req.log.error({ err }, "Failed to get anime");
    res.status(500).json({ error: "Failed to get anime" });
  }
});

export default router;

import { Router } from "express";
import { db } from "@workspace/db";
import { charactersTable, animeTable, evidenceTable } from "@workspace/db";
import { eq, ilike, and, sql } from "drizzle-orm";

const router = Router();

router.get("/characters", async (req, res) => {
  try {
    const animeId = req.query.animeId ? parseInt(req.query.animeId as string) : undefined;
    const search = req.query.search as string | undefined;

    const conditions = [];
    if (animeId) conditions.push(eq(charactersTable.animeId, animeId));
    if (search) conditions.push(ilike(charactersTable.name, `%${search}%`));

    const chars = await db
      .select({
        id: charactersTable.id,
        name: charactersTable.name,
        nameAr: charactersTable.nameAr,
        animeId: charactersTable.animeId,
        animeName: animeTable.name,
        animeNameAr: animeTable.nameAr,
        tier: charactersTable.tier,
        imageUrl: charactersTable.imageUrl,
        powerLevel: charactersTable.powerLevel,
        description: charactersTable.description,
        evidenceCount: sql<number>`(select count(*) from evidence where character_id = ${charactersTable.id})::int`,
      })
      .from(charactersTable)
      .leftJoin(animeTable, eq(charactersTable.animeId, animeTable.id))
      .where(conditions.length > 0 ? and(...conditions) : undefined)
      .orderBy(charactersTable.name);

    res.json(chars);
  } catch (err) {
    req.log.error({ err }, "Failed to list characters");
    res.status(500).json({ error: "Failed to list characters" });
  }
});

router.get("/characters/:id", async (req, res) => {
  try {
    const id = parseInt(req.params.id);
    if (isNaN(id)) return res.status(400).json({ error: "Invalid id" });

    const [char] = await db
      .select({
        id: charactersTable.id,
        name: charactersTable.name,
        nameAr: charactersTable.nameAr,
        animeId: charactersTable.animeId,
        animeName: animeTable.name,
        animeNameAr: animeTable.nameAr,
        tier: charactersTable.tier,
        imageUrl: charactersTable.imageUrl,
        powerLevel: charactersTable.powerLevel,
        description: charactersTable.description,
        evidenceCount: sql<number>`(select count(*) from evidence where character_id = ${charactersTable.id})::int`,
      })
      .from(charactersTable)
      .leftJoin(animeTable, eq(charactersTable.animeId, animeTable.id))
      .where(eq(charactersTable.id, id));

    if (!char) return res.status(404).json({ error: "Character not found" });

    const evidence = await db
      .select()
      .from(evidenceTable)
      .where(eq(evidenceTable.characterId, id))
      .orderBy(evidenceTable.metric);

    res.json({ ...char, evidence, metrics: {} });
  } catch (err) {
    req.log.error({ err }, "Failed to get character");
    res.status(500).json({ error: "Failed to get character" });
  }
});

export default router;

import { Router } from "express";
import { db } from "@workspace/db";
import { evidenceTable } from "@workspace/db";
import { eq, and } from "drizzle-orm";

const router = Router();

router.get("/evidence", async (req, res) => {
  try {
    const characterId = req.query.characterId ? parseInt(req.query.characterId as string) : undefined;
    const metric = req.query.metric as string | undefined;

    if (!characterId) return res.status(400).json({ error: "characterId is required" });

    const conditions = [eq(evidenceTable.characterId, characterId)];
    if (metric) conditions.push(eq(evidenceTable.metric, metric));

    const evidence = await db
      .select()
      .from(evidenceTable)
      .where(and(...conditions))
      .orderBy(evidenceTable.metric);

    res.json(evidence);
  } catch (err) {
    req.log.error({ err }, "Failed to list evidence");
    res.status(500).json({ error: "Failed to list evidence" });
  }
});

export default router;

import { Router } from "express";
